import { useState } from "react";
import { ethers } from "ethers";

export default function VerifyCertificate({ contractAddress, abi }) {
  const [searchId, setSearchId] = useState("");
  const [certData, setCertData] = useState(null);
  const [loading, setLoading] = useState(false);

  async function handleVerify() {
    if (!searchId) return alert("Please enter an ID");
    setLoading(true);
    setCertData(null);

    try {
      const provider = new ethers.providers.Web3Provider(window.ethereum);
      const contract = new ethers.Contract(contractAddress, abi, provider);

      // Must use same conversion as Issue component
      const certIdBytes = ethers.utils.formatBytes32String(searchId);
      
      // Call 'verify' function from your Solidity contract
      const data = await contract.verify(certIdBytes);

      // data[0]=name, data[1]=course, data[2]=ipfs, data[3]=isValid
      if (data[3] === true) { 
        setCertData({
          name: data[0],
          course: data[1],
          ipfs: data[2]
        });
      } else {
        alert("Certificate not found!");
      }
    } catch (error) {
      console.error("Verification Error:", error);
      alert("ID does not exist on this contract.");
    }
    setLoading(false);
  }

  return (
    <div className="card">
      <h3>Verify Certificate</h3>
      <input 
        placeholder="Enter ID (e.g. 101)" 
        onChange={e => setSearchId(e.target.value)} 
      />
      <button onClick={handleVerify} disabled={loading}>
        {loading ? "Searching..." : "Verify Authenticity"}
      </button>

      {certData && (
        <div className="verify-result" style={{marginTop: '20px', padding: '15px', border: '2px solid green'}}>
          <h4>✅ Verified Official</h4>
          <p><strong>Student:</strong> {certData.name}</p>
          <p><strong>Course:</strong> {certData.course}</p>
          <a href={`https://gateway.pinata.cloud/ipfs/${certData.ipfs}`} target="_blank" rel="noreferrer">
            View Certificate File (IPFS)
          </a>
        </div>
      )}
    </div>
  );
}
